from dataclasses import dataclass
from typing import Any, Literal

@dataclass
class StateEdit:
    """Describes one atomic edit to a snapshot."""
    operation: Literal[
        "queue_add", "queue_remove", "queue_reorder",
        "inject_message", "revoke_approval", "grant_approval",
        "correct_tool_result", "update_metadata",
    ]
    payload: dict[str, Any]

def apply_edit(snapshot: "AgentSnapshot", edit: StateEdit) -> "AgentSnapshot":
    """Return a new snapshot with the edit applied (immutable update)."""
    import copy
    snap = copy.deepcopy(snapshot)

    op = edit.operation
    pl = edit.payload

    if op == "queue_add":
        snap.work_queue.append(pl["item"])

    elif op == "queue_remove":
        item_id = pl["item_id"]
        snap.work_queue = [i for i in snap.work_queue if i.get("id") != item_id]

    elif op == "queue_reorder":
        # payload: {"order": ["id1", "id2", ...]}
        order = pl["order"]
        id_to_item = {i["id"]: i for i in snap.work_queue}
        snap.work_queue = [id_to_item[iid] for iid in order if iid in id_to_item]

    elif op == "inject_message":
        # Append as a user message — will be seen on next model call
        snap.messages.append({
            "role": "user",
            "content": pl["content"],
        })

    elif op == "revoke_approval":
        key = pl["key"]
        snap.session_approved = [k for k in snap.session_approved if k != key]

    elif op == "grant_approval":
        key = pl["key"]
        if key not in snap.session_approved:
            snap.session_approved.append(key)

    elif op == "correct_tool_result":
        # Find the most recent tool_result message matching the tool_use_id
        tool_use_id = pl["tool_use_id"]
        new_content = pl["new_content"]
        for msg in reversed(snap.messages):
            if msg.get("role") == "user":
                content = msg.get("content", [])
                if isinstance(content, list):
                    for block in content:
                        if (isinstance(block, dict)
                                and block.get("type") == "tool_result"
                                and block.get("tool_use_id") == tool_use_id):
                            block["content"] = new_content
                            return snap
        raise ValueError(f"tool_use_id {tool_use_id} not found in recent messages")

    elif op == "update_metadata":
        snap.metadata.update(pl)

    else:
        raise ValueError(f"Unknown edit operation: {op}")

    return snap

