def validate_message_list(messages: list[dict]) -> list[str]:
    """Return a list of validation errors; empty list = valid."""
    errors = []
    for i, msg in enumerate(messages):
        role = msg.get("role")
        if role not in ("user", "assistant"):
            errors.append(f"Message {i}: invalid role '{role}'")
        content = msg.get("content")
        if content is None:
            errors.append(f"Message {i}: missing content")
        # Alternating role check (optional but recommended)
        if i > 0:
            prev_role = messages[i-1].get("role")
            if role == prev_role and role != "user":
                errors.append(f"Message {i}: consecutive {role} turns without a {('user' if role=='assistant' else 'assistant')} turn")
    return errors

# Apply validation in apply_edit
def apply_edit_safe(snapshot, edit):
    updated = apply_edit(snapshot, edit)
    errors = validate_message_list(updated.messages)
    if errors:
        raise ValueError(f"Edit produced invalid message list: {errors}")
    return updated

import copy

def diff_snapshots(before: "AgentSnapshot", after: "AgentSnapshot") -> dict:
    """Return a summary of what changed between two snapshots."""
    changes = {}

    if before.messages != after.messages:
        added = len(after.messages) - len(before.messages)
        changes["messages"] = {
            "before_count": len(before.messages),
            "after_count": len(after.messages),
            "added": added,
            "new_content": [
                m.get("content", "")[:200]
                for m in after.messages[len(before.messages):]
            ],
        }

    if before.work_queue != after.work_queue:
        before_ids = {i.get("id") for i in before.work_queue}
        after_ids  = {i.get("id") for i in after.work_queue}
        changes["work_queue"] = {
            "added":   list(after_ids - before_ids),
            "removed": list(before_ids - after_ids),
            "reordered": before.work_queue != after.work_queue and before_ids == after_ids,
        }

    if set(before.session_approved) != set(after.session_approved):
        changes["session_approved"] = {
            "granted": list(set(after.session_approved) - set(before.session_approved)),
            "revoked": list(set(before.session_approved) - set(after.session_approved)),
        }

    if before.metadata != after.metadata:
        changes["metadata"] = {"keys_changed": list(after.metadata.keys())}

    return changes


