class BatchEditRequest(BaseModel):
    edits: list[EditRequest]
    reason: str = ""

@app.post("/agents/{agent_id}/checkpoints/{snapshot_id}/edit-batch")
async def batch_edit_snapshot(agent_id: str, snapshot_id: str, body: BatchEditRequest):
    snapshot = await store.load(snapshot_id)
    if not snapshot or snapshot.agent_id != agent_id:
        raise HTTPException(404, "Snapshot not found")

    updated = snapshot
    applied = []
    for req in body.edits:
        edit = StateEdit(operation=req.operation, payload=req.payload)
        try:
            updated = apply_edit_safe(updated, edit)
            applied.append(req.operation)
        except (ValueError, KeyError) as e:
            raise HTTPException(400, f"Edit '{req.operation}' failed: {e}")

    diff = diff_snapshots(snapshot, updated)
    await store.save(updated)

    _log_state_edit(agent_id, snapshot_id, f"batch:{','.join(applied)}", body.reason)
    return {"applied": applied, "diff": diff}
